import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as i,c as l,e as r}from"./app-757930e5.js";const a={},_=r('<p>主键必然是唯一且不为空，但是唯一不一定是主键，而且主键只能有一个，但是唯一约束仅仅是为了保持某些列具有唯一性而已。所以可以有多列<br> 一张表里只能有一个主键约束，可以有多个唯一约束<br> 主键约束的字段不能为null，而唯一约束的字段可以为null值</p><h3 id="主键约束-primary-key" tabindex="-1"><a class="header-anchor" href="#主键约束-primary-key" aria-hidden="true">#</a> 主键约束（PRIMARY KEY）</h3><ol><li>主键用于唯一地标识表中的每一条记录，可以定义一列或多列为主键。</li><li>是不可能（或很难）更新．</li><li>主键列上没有任何两行具有相同值（即重复值），不允许空（NULL）．</li><li>主健可作外健，唯一索引不可；</li></ol><h3 id="唯一性约束-unique" tabindex="-1"><a class="header-anchor" href="#唯一性约束-unique" aria-hidden="true">#</a> 唯一性约束（UNIQUE）</h3><ol><li>唯一性约束用来限制不受主键约束的列上的数据的唯一性，用于作为访问某行的可选手段，一个表上可以放置多个唯一性约束．</li><li>只要唯一就可以更新．</li><li>即表中任意两行在 指定列上都不允许有相同的值，允许空（NULL）．</li><li>一个表上可以放置多个唯一性约束</li></ol>',5),t=[_];function o(n,c){return i(),l("div",null,t)}const h=e(a,[["render",o],["__file","主键约束和唯一性约束的区别-927fbb2b.html.vue"]]);export{h as default};
